import{_ as t}from"./chunks/feature-mapping-step1.DSj0Hfx_.js";import{_ as o,o as a,c as r,ag as n}from"./chunks/framework.1N8rnUr9.js";const s="/tubebay/assets/installation-step.D69uJ7ZC.png",i="/tubebay/assets/onboarding-welcome.5ts9qp_I.png",l="/tubebay/assets/wizard-step1a.BCM_CFT4.png",d="/tubebay/assets/wizard-step1b.lTibvmGh.png",u="/tubebay/assets/wizard-step-done.DABqmG9a.png",c="/tubebay/assets/feature-preview.DF6H7tLp.png",S=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1775898496000}'),h={name:"guide/getting-started.md"};function p(g,e,b,y,m,f){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>Welcome to <strong>TubeBay</strong>! This guide will help you install, connect, and start showcasing your YouTube content on your WooCommerce store in minutes.</p><h2 id="_1-installation" tabindex="-1">1. Installation <a class="header-anchor" href="#_1-installation" aria-label="Permalink to &quot;1. Installation&quot;">​</a></h2><p>First, ensure you have the plugin installed and activated. You can find TubeBay under the <strong>Plugins</strong> section of your WordPress dashboard.</p><p><img src="'+s+'" alt="Installing TubeBay"></p><h2 id="_2-welcome-onboarding" tabindex="-1">2. Welcome &amp; Onboarding <a class="header-anchor" href="#_2-welcome-onboarding" aria-label="Permalink to &quot;2. Welcome &amp; Onboarding&quot;">​</a></h2><p>Once activated, navigate to <strong>TubeBay</strong> in your WordPress sidebar. You will be greeted by the <strong>Welcome to TubeBay</strong> onboarding screen, designed to get you up and running in seconds.</p><p><img src="'+i+'" alt="Onboarding Welcome Screen"></p><p>You have two choices on this screen:</p><ul><li><strong>Start Setup Wizard</strong>: Recommended for most users. This will guide you through connecting your YouTube account step-by-step.</li><li><strong>Skip Setup &amp; Go to Settings</strong>: Best for advanced users who want to manually configure API keys or other global settings immediately.</li></ul><h2 id="_3-the-setup-wizard" tabindex="-1">3. The Setup Wizard <a class="header-anchor" href="#_3-the-setup-wizard" aria-label="Permalink to &quot;3. The Setup Wizard&quot;">​</a></h2><p>If you choose the wizard, you will be guided through three simple steps to get TubeBay running.</p><h3 id="step-1-connect-youtube" tabindex="-1">Step 1: Connect YouTube <a class="header-anchor" href="#step-1-connect-youtube" aria-label="Permalink to &quot;Step 1: Connect YouTube&quot;">​</a></h3><p>You can choose between <strong>Google OAuth</strong> (recommended) or <strong>Manual Setup</strong>. For most users, OAuth is the easiest:</p><ol><li>Click the <strong>Sign in with Google</strong> button.</li></ol><p><img src="'+l+'" alt="Wizard Step 1: Connect Account"></p><ol start="2"><li>A new tab will open. Authorize your account and copy the <strong>Access Code</strong> provided.</li><li>Return to the wizard and paste the code into the <strong>Access Code</strong> field.</li></ol><p><img src="'+d+'" alt="Wizard Step 1: Enter Access Code"></p><ol start="4"><li>Click <strong>Connect Account</strong>.</li></ol><h3 id="step-2-configure-settings" tabindex="-1">Step 2: Configure Settings <a class="header-anchor" href="#step-2-configure-settings" aria-label="Permalink to &quot;Step 2: Configure Settings&quot;">​</a></h3><p>Once connected, you can set your global video preferences. These settings will apply to all mapped videos unless overridden individually:</p><ol><li><p><strong>Global Video Placement</strong>: Choose where videos should appear by default on your product pages (e.g., &quot;Main Gallery&quot;). Click <strong>Preview</strong> to see how it looks.</p></li><li><p><strong>Muted Autoplay</strong>: Toggle whether videos should play automatically without sound when the page loads.</p></li><li><p><strong>Show Player Controls</strong>: Choose whether to display the standard YouTube playback controls.</p></li><li><p>Click <strong>Save &amp; Finish</strong> to complete the wizard.</p></li></ol><h3 id="step-3-done" tabindex="-1">Step 3: Done! <a class="header-anchor" href="#step-3-done" aria-label="Permalink to &quot;Step 3: Done!&quot;">​</a></h3><p>Congratulations! Your account is connected and your global settings are configured. You are now ready to start syncing and mapping videos.</p><p><img src="'+u+'" alt="Wizard Completion"></p><h2 id="_4-sync-your-library" tabindex="-1">4. Sync Your Library <a class="header-anchor" href="#_4-sync-your-library" aria-label="Permalink to &quot;4. Sync Your Library&quot;">​</a></h2><p>After connecting, TubeBay will automatically fetch your video library. You can monitor the progress on the dashboard.</p><h2 id="_5-map-videos-to-products" tabindex="-1">5. Map Videos to Products <a class="header-anchor" href="#_5-map-videos-to-products" aria-label="Permalink to &quot;5. Map Videos to Products&quot;">​</a></h2><p>Now the fun part! Go to <strong>Products &gt; All Products</strong> and edit a product. In the sidebar, you&#39;ll find the <strong>TubeBay Video</strong> box where you can select a video from your library.</p><p><img src="'+t+'" alt="Product Page Mapping UI"></p><h2 id="_6-configure-the-video-player" tabindex="-1">6. Configure the Video Player <a class="header-anchor" href="#_6-configure-the-video-player" aria-label="Permalink to &quot;6. Configure the Video Player&quot;">​</a></h2><p>Before viewing the video on the frontend, check how it should behave:</p><ol><li>Navigate to <strong>TubeBay &gt; Settings</strong>.</li><li>Go to the <strong>Video Player</strong> tab.</li><li>Set your preferred <strong>Placement</strong> (e.g., &quot;Below Product Gallery&quot;).</li><li>Toggle options like <strong>Muted Autoplay</strong> or <strong>Hide Controls</strong>.</li><li>Click <strong>Save Settings</strong>.</li></ol><h2 id="_7-showcase-on-your-site" tabindex="-1">7. Showcase on Your Site <a class="header-anchor" href="#_7-showcase-on-your-site" aria-label="Permalink to &quot;7. Showcase on Your Site&quot;">​</a></h2><p>Visit the product page you just mapped a video to. You should see the TubeBay player embedded in your chosen location! You can also use <strong>Shortcodes</strong> to place videos anywhere else on your site!</p><p><img src="'+c+'" alt="Product Page Preview"></p><h2 id="what-s-next" tabindex="-1">What&#39;s Next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next?&quot;">​</a></h2><ul><li>Learn more about <a href="/tubebay/guide/connection.html">Connection Methods</a>.</li><li>Optimize your <a href="/tubebay/guide/sync-library.html">Sync Schedule</a>.</li><li>Explore <a href="/tubebay/features/shortcodes.html">Shortcodes</a> for custom video placement.</li></ul>',38)])])}const P=o(h,[["render",p]]);export{S as __pageData,P as default};
